impl Solution {
    pub fn sum_subarray_mins(arr: Vec<i32>) -> i32 {
        const MOD: i64 = 1_000_000_007;
        let n = arr.len();
        let mut left = vec![0i32; n];
        let mut right = vec![0i32; n];
        let mut stack: Vec<usize> = Vec::new();
        for i in 0..n {
            while let Some(&top) = stack.last() {
                if arr[top] > arr[i] { stack.pop(); } else { break; }
            }
            left[i] = stack.last().map(|&x| x as i32).unwrap_or(-1);
            stack.push(i);
        }
        stack.clear();
        for i in (0..n).rev() {
            while let Some(&top) = stack.last() {
                if arr[top] >= arr[i] { stack.pop(); } else { break; }
            }
            right[i] = stack.last().map(|&x| x as i32).unwrap_or(n as i32);
            stack.push(i);
        }
        let mut result: i64 = 0;
        for i in 0..n {
            result = (result + arr[i] as i64 * (i as i64 - left[i] as i64) * (right[i] as i64 - i as i64)) % MOD;
        }
        result as i32
    }
